import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./../styles/Auth.css";

const Signup = () => {
  const [name, setName] = useState("");
  const [userType, setUserType] = useState("Student");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [libraryId, setLibraryId] = useState(""); // Store Library ID
  const [showModal, setShowModal] = useState(false); // Control modal visibility
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    const response = await fetch("http://localhost:5000/auth/signup", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name, userType, email, password }), // Remove libraryId
    });

    const data = await response.json();
    if (response.ok) {
      setLibraryId(data.libraryId); // Store library ID
      setShowModal(true); // Show modal
    } else {
      setError(data.message);
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    navigate("/login"); // Redirect after closing modal
  };

  return (
    <div className="auth-container">
      <div className="auth-box">
        <h2>📖 Library Signup</h2>
        {error && <p className="error">{error}</p>}
        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Full Name" value={name} onChange={(e) => setName(e.target.value)} required />
          <select value={userType} onChange={(e) => setUserType(e.target.value)} required>
            <option value="Student">Student</option>
            <option value="Faculty">Faculty</option>
            <option value="Librarian">Librarian</option>
          </select>
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
          <button type="submit">Sign Up</button>
        </form>
        <p>Already a member? <span onClick={() => navigate("/login")}>Login</span></p>
      </div>
    </div>
  );
};

export default Signup;
